using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Services;

public class ServerShipmentService : IShipmentService
{
    private static readonly List<Shipment> Shipments =
    [
        new() { Id = 1, TrackingNumber = "TRK-100201", Origin = "New York, US", Destination = "London, UK", Status = ShipmentStatus.InTransit, ShippedDate = DateTime.UtcNow.AddDays(-3), EstimatedDelivery = DateTime.UtcNow.AddDays(2), CustomerName = "Alice Johnson", CustomerEmail = "alice@example.com" },
        new() { Id = 2, TrackingNumber = "TRK-100202", Origin = "Shanghai, CN", Destination = "Los Angeles, US", Status = ShipmentStatus.OutForDelivery, ShippedDate = DateTime.UtcNow.AddDays(-7), EstimatedDelivery = DateTime.UtcNow.AddDays(0), CustomerName = "Bob Smith", CustomerEmail = "bob@example.com" },
        new() { Id = 3, TrackingNumber = "TRK-100203", Origin = "Berlin, DE", Destination = "Tokyo, JP", Status = ShipmentStatus.Pending, ShippedDate = DateTime.UtcNow, EstimatedDelivery = DateTime.UtcNow.AddDays(5), CustomerName = "Yuki Tanaka", CustomerEmail = "yuki@example.com" },
        new() { Id = 4, TrackingNumber = "TRK-100204", Origin = "Sydney, AU", Destination = "Mumbai, IN", Status = ShipmentStatus.Delivered, ShippedDate = DateTime.UtcNow.AddDays(-10), EstimatedDelivery = DateTime.UtcNow.AddDays(-2), CustomerName = "Raj Patel", CustomerEmail = "raj@example.com" },
        new() { Id = 5, TrackingNumber = "TRK-100205", Origin = "São Paulo, BR", Destination = "Paris, FR", Status = ShipmentStatus.Delayed, ShippedDate = DateTime.UtcNow.AddDays(-5), EstimatedDelivery = DateTime.UtcNow.AddDays(3), CustomerName = "Marie Dupont", CustomerEmail = "marie@example.com" },
    ];

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return Task.FromResult(Shipments.ToList());
    }

    public Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = Shipments.FirstOrDefault(s =>
            s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = Shipments.FirstOrDefault(s => s.Id == id);
        if (shipment is not null)
            shipment.Status = newStatus;
        return Task.CompletedTask;
    }
}

using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (IShipmentService service) =>
            Results.Ok(await service.GetAllShipmentsAsync()));

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
        });

        group.MapPut("{id}/status", async (int id, ShipmentStatus newStatus, IShipmentService service) =>
        {
            await service.UpdateShipmentStatusAsync(id, newStatus);
            return Results.NoContent();
        });
    }
}

